 37→/**
 38→ * The card template previewer intent must supply one or more cards to show and the index in the list from where
 39→ * to begin showing them. Special rules are applied if the list size is 1 (i.e., no scrolling
 40→ * buttons will be shown).
 41→ */
 42→@NeedsTest("after switch to new schema as default, add test to confirm audio tags rendered")
 43→open class CardTemplatePreviewer : AbstractFlashcardViewer() {
 44→    private var mEditedModelFileName: String? = null
 45→    private var mEditedNotetype: NotetypeJson? = null
 46→    private var mOrdinal = 0
 47→
 48→    /** The index of the card in cardList to show  */
 49→    private var mCardListIndex = 0
 50→
 51→    /** The list (currently singular) of cards to be previewed
 52→     * A single template was selected, and there was an associated card which exists
 53→     */
 54→    private var mCardList: LongArray? = null
 55→    private var mNoteEditorBundle: Bundle? = null
 56→    private var mShowingAnswer = false
 57→
 58→    /**
 59→     * The number of valid cards for the note
 60→     * Only used if mNoteEditorBundle != null
 61→     *
 62→     * If launched from the Template Editor, only one the selected card template is selectable
 63→     */
 64→    private var cardCount = 0
 65→
 66→    /**
 67→     * The index of the selected card in the previewer. Used for forward/back
 68→     * For cloze note types, this may not be the same as `ord`: `{{c1::A}} {{c3::B}}`
 69→     */
 70→    var cardIndex = 0
 71→        private set
 72→    private var mAllFieldsNull = true
 73→    private var mCardType: String? = null
 74→    protected var previewLayout: PreviewLayout? = null
 75→    override fun onCreate(savedInstanceState: Bundle?) {
 76→        if (showedActivityFailedScreen(savedInstanceState)) {
 77→            return
 78→        }
 79→        super.onCreate(savedInstanceState)
 80→        var parameters = savedInstanceState
 81→        if (parameters == null) {
 82→            parameters = intent.extras
 83→        }
 84→        if (parameters != null) {
 85→            mNoteEditorBundle = parameters.getBundle("noteEditorBundle")
 86→            mEditedModelFileName = parameters.getString(CardTemplateNotetype.INTENT_MODEL_FILENAME)
 87→            mCardList = parameters.getLongArray("cardList")
 88→            mOrdinal = parameters.getInt("ordinal")
 89→            mCardListIndex = parameters.getInt("cardListIndex")
 90→            mShowingAnswer = parameters.getBoolean("showingAnswer", mShowingAnswer)
 91→        }
 92→        if (mEditedModelFileName != null) {
 93→            Timber.d("onCreate() loading edited model from %s", mEditedModelFileName)
 94→            try {
 95→                mEditedNotetype = CardTemplateNotetype.getTempModel(mEditedModelFileName!!)
 96→                mCardType = mEditedNotetype!!.optString("name")
 97→            } catch (e: IOException) {
 98→                Timber.w(e, "Unable to load temp model from file %s", mEditedModelFileName)
 99→                closeCardTemplatePreviewer()
100→            }
101→        }
102→        showBackIcon()
103→        // Ensure navigation drawer can't be opened. Various actions in the drawer cause crashes.
104→        disableDrawerSwipe()
105→        startLoadingCollection()
106→    }
107→
108→    override fun onResume() {
109→        super.onResume()
110→        if (currentCard == null || mOrdinal < 0) {
111→            Timber.e("CardTemplatePreviewer started with empty card list or invalid index")
112→            closeCardTemplatePreviewer()
113→        }
114→    }
115→
116→    private fun closeCardTemplatePreviewer() {
117→        Timber.d("CardTemplatePreviewer:: closeCardTemplatePreviewer()")
118→        setResult(RESULT_OK)
119→        CardTemplateNotetype.clearTempModelFiles()
120→        finishWithAnimation(ActivityTransitionAnimation.Direction.END)
121→    }
122→
123→    @Suppress("DEPRECATION", "Deprecated in API34+dependencies for predictive back feature")
124→    override fun onBackPressed() {
125→        Timber.i("CardTemplatePreviewer:: onBackPressed()")
126→        super.onBackPressed()
127→        closeCardTemplatePreviewer()
128→    }
129→
130→    override fun performReload() {
131→        // This should not happen.
132→        finishWithAnimation(ActivityTransitionAnimation.Direction.END)
133→    }
134→
135→    override fun onNavigationPressed() {
136→        Timber.i("CardTemplatePreviewer:: Navigation button pressed")
137→        closeCardTemplatePreviewer()
138→    }
139→
140→    override fun initLayout() {
141→        super.initLayout()
142→        topBarLayout!!.visibility = View.GONE
143→        findViewById<View>(R.id.answer_options_layout).visibility = View.GONE
144→        findViewById<View>(R.id.bottom_area_layout).visibility = View.VISIBLE
145→        previewLayout = createAndDisplay(this, mToggleAnswerHandler)
146→        previewLayout!!.setOnPreviousCard { onPreviousCard() }
147→        previewLayout!!.setOnNextCard { onNextCard() }
148→        previewLayout!!.hideNavigationButtons()
149→        previewLayout!!.setPrevButtonEnabled(false)
150→    }
151→
152→    override fun displayCardQuestion() {
153→        super.displayCardQuestion()
154→        mShowingAnswer = false
155→        previewLayout!!.setShowingAnswer(false)
156→    }
157→
158→    override fun displayCardAnswer() {
159→        if (mAllFieldsNull && mCardType != null && mCardType == getString(R.string.basic_typing_model_name)) {
160→            answerField!!.setText(getString(R.string.basic_answer_sample_text_user))
161→        }
162→        super.displayCardAnswer()
163→        mShowingAnswer = true
164→        previewLayout!!.setShowingAnswer(true)
165→    }
166→
167→    override fun hideEaseButtons() {
168→        /* do nothing */
169→    }
170→
171→    override fun displayAnswerBottomBar() {
172→        /* do nothing */
173→    }
174→
175→    private val mToggleAnswerHandler = View.OnClickListener {
176→        if (mShowingAnswer) {
177→            displayCardQuestion()
178→        } else {
179→            displayCardAnswer()
180→        }
181→    }
182→
183→    /** When the next template is requested  */
184→    fun onNextCard() {
185→        var index = cardIndex
186→        if (!isNextBtnEnabled(index)) {
187→            return
188→        }
189→        cardIndex = ++index
190→        onCardIndexChanged()
191→    }
192→
193→    /** When the previous template is requested  */
194→    fun onPreviousCard() {
195→        var index = cardIndex
196→        if (!isPrevBtnEnabled(index)) {
197→            return
198→        }
199→        cardIndex = --index
200→        onCardIndexChanged()
201→    }
202→
203→    /**
204→     * Loads the next card after the current card index has been changed
205→     */
206→    private fun onCardIndexChanged() {
207→        val prevBtnEnabled = isPrevBtnEnabled(cardIndex)
208→        val nextBtnEnabled = isNextBtnEnabled(cardIndex)
209→        previewLayout!!.setPrevButtonEnabled(prevBtnEnabled)
210→        previewLayout!!.setNextButtonEnabled(nextBtnEnabled)
211→        setCurrentCardFromNoteEditorBundle(getColUnsafe)
212→        displayCardQuestion()
213→    }
214→
215→    private fun isPrevBtnEnabled(cardIndex: Int): Boolean {
216→        return cardIndex > 0
217→    }
218→
219→    private fun isNextBtnEnabled(cardIndex: Int): Boolean {
220→        return cardIndex < cardCount - 1
221→    }
222→
223→    public override fun onSaveInstanceState(outState: Bundle) {
224→        outState.putString(CardTemplateNotetype.INTENT_MODEL_FILENAME, mEditedModelFileName)
225→        outState.putLongArray("cardList", mCardList)
226→        outState.putInt("ordinal", mOrdinal)
227→        outState.putInt("cardListIndex", mCardListIndex)
228→        outState.putBundle("noteEditorBundle", mNoteEditorBundle)
229→        outState.putBoolean("showingAnswer", mShowingAnswer)
230→        super.onSaveInstanceState(outState)
231→    }
232→
233→    override fun onCollectionLoaded(col: Collection) {
234→        super.onCollectionLoaded(col)
235→        if (mNoteEditorBundle != null) {
236→            mAllFieldsNull = false
237→            // loading from the note editor
238→            val toPreview = setCurrentCardFromNoteEditorBundle(col)
239→            if (toPreview != null) {
240→                cardCount = toPreview.note().numberOfCardsEphemeral()
241→                if (cardCount >= 2) {
242→                    previewLayout!!.showNavigationButtons()
243→                }
244→            }
245→        } else {
246→            // loading from the card template editor
247→            mAllFieldsNull = true
248→            // card template with associated card due to opening from note editor
249→            if (mCardList != null && mCardListIndex >= 0 && mCardListIndex < mCardList!!.size) {
250→                currentCard = PreviewerCard(col, mCardList!![mCardListIndex])
251→            } else if (mEditedNotetype != null) { // bare note type (not coming from note editor), or new card template
252→                Timber.d("onCreate() CardTemplatePreviewer started with edited model and template index, displaying blank to preview formatting")
253→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
254→                if (currentCard == null) {
255→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
256→                    closeCardTemplatePreviewer()
257→                }
258→            }
259→        }
260→        if (currentCard == null) {
261→            showThemedToast(applicationContext, getString(R.string.invalid_template), false)
262→            closeCardTemplatePreviewer()
263→            return
264→        }
265→        displayCardQuestion()
266→        if (mShowingAnswer) {
267→            displayCardAnswer()
268→        }
269→        showBackIcon()
270→    }
271→
272→    protected fun getCard(col: Collection, cardListIndex: Long): Card {
273→        return PreviewerCard(col, cardListIndex)
274→    }
275→
276→    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
277→        assert(mNoteEditorBundle != null)
278→        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
279→        // example: a basic card with no fields provided
280→        if (currentCard == null) {
281→            return null
282→        }
283→        val newDid = mNoteEditorBundle!!.getLong("did")
284→        if (col.decks.isDyn(newDid)) {
285→            currentCard!!.oDid = currentCard!!.did
286→        }
287→        currentCard!!.did = newDid
288→        val currentNote = currentCard!!.note()
289→        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
290→        setTags(currentNote, tagsList)
291→        return currentCard
292→    }
293→
294→    /**
295→     * Set the set tags of currentNote to tagsList.  We make no
296→     * assumption on the content of tagsList, except that its strings
297→     * are valid tags (i.e. no spaces in it).
298→     */
299→    private fun setTags(currentNote: Note, tagsList: List<String>?) {
300→        val currentTags = currentNote.tags.toTypedArray()
301→        for (tag in currentTags) {
302→            currentNote.delTag(tag)
303→        }
304→        if (tagsList != null) {
305→            val tagsSet = currentNote.col.tags.canonify(tagsList)
306→            currentNote.addTags(tagsSet)
307→        }
308→    }
309→
310→    private fun getLabels(fieldValues: MutableList<String>) {
311→        if (mCardType != null && mCardType == getString(R.string.cloze_model_name)) {
312→            fieldValues[0] = getString(R.string.cloze_sample_text, "c1")
313→        }
314→        if (mCardType != null && mCardType == getString(R.string.basic_typing_model_name)) {
315→            fieldValues[1] = getString(R.string.basic_answer_sample_text)
316→        }
317→    }
318→
319→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
320→        val noteFields = noteEditorBundle!!.getBundle("editFields")
321→            ?: return mutableListOf()
322→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
323→        // so convert this to a list of strings, with null in place of the invalid fields
324→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
325→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
326→        for (fieldOrd in noteFields.keySet()) {
327→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
328→        }
329→        return mutableListOf(*ret)
330→    }
331→
332→    /**
333→     * This method generates a note from a sample model, or fails if invalid
334→     * @param index The index in the templates for the model. NOT `ord`
335→     */
336→    fun getDummyCard(notetype: NotetypeJson, index: Int): Card? {
337→        return getDummyCard(notetype, index, notetype.fieldsNames.toMutableList())
338→    }
339→
340→    /**
341→     * This method generates a note from a sample model, or fails if invalid
342→     * @param cardIndex The index in the templates for the model. NOT `ord`
343→     */
344→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
345→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
346→        if (notetype == null) {
347→            return null
348→        }
349→        if (mAllFieldsNull) {
350→            getLabels(fieldValues)
351→        }
352→        val n = getColUnsafe.newNote(notetype)
353→        var i = 0
354→        while (i < fieldValues.size && i < n.fields.size) {
355→            if (mAllFieldsNull) {
356→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
357→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
358→                ) {
359→                    n.setField(i, fieldValues[i])
360→                } else {
361→                    n.setField(i, "(" + fieldValues[i] + ")")
362→                }
363→            } else {
364→                n.setField(i, fieldValues[i])
365→            }
366→            i++
367→        }
368→        try {
369→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
370→        } catch (e: Exception) {
371→            // Calling code handles null return, so we can log this for developer's interest but move on
372→            Timber.d(e, "getDummyCard() unable to create card")
373→        }
374→        return null
375→    }
376→
377→    /** Override certain aspects of Card behavior so we may display unsaved data  */
378→    inner class PreviewerCard : Card {
379→        private val mNote: Note?
380→
381→        constructor(col: Collection, id: Long) : super(col, id) {
382→            mNote = null
383→        }
384→
385→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
386→            reload: Boolean
387→        ): Note {
388→            return mNote ?: super.note(reload)
389→        }
390→
391→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
392→        override fun note(): Note {
393→            return mNote ?: super.note()
394→        }
395→
396→        /** if we have an unsaved note, never return empty  */
397→        val isEmpty: Boolean
398→            get() = mNote != null
399→
400→        /** Override the method that fetches the model so we can render unsaved models  */
401→        override fun model(): NotetypeJson {
402→            return mEditedNotetype ?: super.model()
403→        }
404→
405→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
406→            if (renderOutput == null || reload) {
407→                val index = if (model().isCloze) {
408→                    0
409→                } else {
410→                    ord
411→                }
412→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
413→                    note(),
414→                    this,
415→                    model(),
416→                    model().getJSONArray("tmpls")[index] as JSONObject,
417→                    fillEmpty = false
418→                )
419→                renderOutput =
420→                    context.render()
421→            }
422→            return renderOutput!!
423→        }
424→    }
425→}
426→
427→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
428→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
429→        return this.renderOutput!!
430→    }
431→    companion object {
432→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
433→            val card = EphemeralCard(col, null)
434→            card.did = 1
435→            card.ord = n.cardIndexToOrd(cardIndex)
436→
437→            val nt = n.notetype
438→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
439→                0
440→            } else {
441→                cardIndex
442→            }
443→            val template = nt.tmpls[templateIdx] as JSONObject
444→            template.put("ord", card.ord)
445→
446→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
447→                n,
448→                card,
449→                notetype = nt,
450→                template = template,
451→                fillEmpty = false
452→            ).render()
453→            card.renderOutput = output
454→            card.setNote(n)
455→            return card
456→        }
457→    }
458→}
459→
460→/** returns the number of cards from a note which has not had data saved in the database */
461→private fun Note.numberOfCardsEphemeral(): Int {
462→    // We can't use note.numberOfCards() as this uses the database value
463→    return when {
464→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
465→        else -> notetype.templatesNames.size
466→    }
467→}
468→
469→/**
470→ * Given a card index, returns the 'ord' of the card
471→ */
472→private fun Note.cardIndexToOrd(index: Int): Int {
473→    // We can't use note.numberOfCards() as this uses the database value
474→    return when {
475→        this.notetype.isCloze -> col.clozeNumbersInNote(this)[index] - 1
476→        else -> index
477→    }
478→}
