337→    /**
338→     * Computes the initial card index from the ordinal value passed from the note editor.
339→     * For cloze note types, ordinal (ord) is different from card index.
340→     * For example, with `{{c1::A}} {{c3::B}}`, ord 2 (c3) corresponds to card index 1.
341→     */
342→    private fun getInitialCardIndexFromOrdinal(col: Collection): Int {
343→        if (mEditedNotetype == null) {
344→            return 0
345→        }
346→        val fieldValues = getBundleEditFields(mNoteEditorBundle)
347→        if (fieldValues.isEmpty()) {
348→            return 0
349→        }
350→        val n = col.newNote(mEditedNotetype!!)
351→        var i = 0
352→        while (i < fieldValues.size && i < n.fields.size) {
353→            n.setField(i, fieldValues[i])
354→            i++
355→        }
356→        return n.ordToCardIndex(mOrdinal)
357→    }
