371→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
372→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
373→        if (notetype == null) {
374→            return null
375→        }
376→        if (mAllFieldsNull) {
377→            getLabels(fieldValues)
378→        }
379→        val n = getColUnsafe.newNote(notetype)
380→        var i = 0
381→        while (i < fieldValues.size && i < n.fields.size) {
382→            if (mAllFieldsNull) {
383→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
384→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
385→                ) {
386→                    n.setField(i, fieldValues[i])
387→                } else {
388→                    n.setField(i, "(" + fieldValues[i] + ")")
389→                }
390→            } else {
391→                n.setField(i, fieldValues[i])
392→            }
393→            i++
394→        }
395→        try {
396→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
397→        } catch (e: Exception) {
398→            // Calling code handles null return, so we can log this for developer's interest but move on
399→            Timber.d(e, "getDummyCard() unable to create card")
400→        }
401→        return null
402→    }
