454→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
455→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
456→        return this.renderOutput!!
457→    }
458→    companion object {
459→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
460→            val card = EphemeralCard(col, null)
461→            card.did = 1
462→            card.ord = n.cardIndexToOrd(cardIndex)
463→
464→            val nt = n.notetype
465→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
466→                0
467→            } else {
468→                cardIndex
469→            }
470→            val template = nt.tmpls[templateIdx] as JSONObject
471→            template.put("ord", card.ord)
472→
473→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
474→                n,
475→                card,
476→                notetype = nt,
477→                template = template,
478→                fillEmpty = false
479→            ).render()
480→            card.renderOutput = output
481→            card.setNote(n)
482→            return card
483→        }
484→    }
485→}
