276→    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
277→        assert(mNoteEditorBundle != null)
278→        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
279→        // example: a basic card with no fields provided
280→        if (currentCard == null) {
281→            return null
282→        }
283→        val newDid = mNoteEditorBundle!!.getLong("did")
284→        if (col.decks.isDyn(newDid)) {
285→            currentCard!!.oDid = currentCard!!.did
286→        }
287→        currentCard!!.did = newDid
288→        val currentNote = currentCard!!.note()
289→        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
290→        setTags(currentNote, tagsList)
291→        return currentCard
292→    }
