404→    /** Override certain aspects of Card behavior so we may display unsaved data  */
405→    inner class PreviewerCard : Card {
406→        private val mNote: Note?
407→
408→        constructor(col: Collection, id: Long) : super(col, id) {
409→            mNote = null
410→        }
411→
412→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
413→            reload: Boolean
414→        ): Note {
415→            return mNote ?: super.note(reload)
416→        }
417→
418→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
419→        override fun note(): Note {
420→            return mNote ?: super.note()
421→        }
422→
423→        /** if we have an unsaved note, never return empty  */
424→        val isEmpty: Boolean
425→            get() = mNote != null
426→
427→        /** Override the method that fetches the model so we can render unsaved models  */
428→        override fun model(): NotetypeJson {
429→            return mEditedNotetype ?: super.model()
430→        }
431→
432→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
433→            if (renderOutput == null || reload) {
434→                val index = if (model().isCloze) {
435→                    0
436→                } else {
437→                    ord
438→                }
439→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
440→                    note(),
441→                    this,
442→                    model(),
443→                    model().getJSONArray("tmpls")[index] as JSONObject,
444→                    fillEmpty = false
445→                )
446→                renderOutput =
447→                    context.render()
448→            }
449→            return renderOutput!!
450→        }
451→    }
452→}
453→
454→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
455→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
456→        return this.renderOutput!!
457→    }
458→    companion object {
459→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
460→            val card = EphemeralCard(col, null)
461→            card.did = 1
462→            card.ord = n.cardIndexToOrd(cardIndex)
463→
464→            val nt = n.notetype
465→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
466→                0
467→            } else {
468→                cardIndex
469→            }
470→            val template = nt.tmpls[templateIdx] as JSONObject
471→            template.put("ord", card.ord)
472→
473→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
474→                n,
475→                card,
476→                notetype = nt,
477→                template = template,
478→                fillEmpty = false
479→            ).render()
480→            card.renderOutput = output
481→            card.setNote(n)
482→            return card
483→        }
484→    }
485→}
