487→/** returns the number of cards from a note which has not had data saved in the database */
488→private fun Note.numberOfCardsEphemeral(): Int {
489→    // We can't use note.numberOfCards() as this uses the database value
490→    return when {
491→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
492→        else -> notetype.templatesNames.size
493→    }
494→}
495→
496→/**
497→ * Given a card index, returns the 'ord' of the card
498→ */
499→private fun Note.cardIndexToOrd(index: Int): Int {
500→    // We can't use note.numberOfCards() as this uses the database value
501→    return when {
502→        this.notetype.isCloze -> col.clozeNumbersInNote(this)[index] - 1
503→        else -> index
504→    }
505→}
506→
507→/**
508→ * Given a card 'ord', returns the card index
509→ * This is the reverse of [cardIndexToOrd]
510→ */
511→private fun Note.ordToCardIndex(ord: Int): Int {
512→    return when {
513→        this.notetype.isCloze -> {
514→            val clozeNumbers = col.clozeNumbersInNote(this)
515→            // ord is 0-indexed, cloze numbers are 1-indexed
516→            val index = clozeNumbers.indexOf(ord + 1)
517→            // If not found (e.g., empty card), default to 0
518→            if (index >= 0) index else 0
519→        }
520→        else -> ord
521→    }
522→}
